/**
 * @summary Back Office health check
 */
export type healthCheckResponse200 = {
  data: void
  status: 200
}

export type healthCheckResponseSuccess = (healthCheckResponse200) & {
  headers: Headers;
};
;

export type healthCheckResponse = (healthCheckResponseSuccess)

export const getHealthCheckUrl = () => {


  

  return `/bo/health`
}

export const healthCheck = async ( options?: RequestInit): Promise<healthCheckResponse> => {
  
  return fetcher<healthCheckResponse>(getHealthCheckUrl(),
  {      
    ...options,
    method: 'GET'
    
    
  }
);}
  


/**
 * @summary BO username login (httpOnly cookie)
 */
export type loginResponse200 = {
  data: Login200
  status: 200
}

export type loginResponse400 = {
  data: Login400
  status: 400
}

export type loginResponse401 = {
  data: Login401
  status: 401
}

export type loginResponse403 = {
  data: Login403
  status: 403
}

export type loginResponse404 = {
  data: Login404
  status: 404
}

export type loginResponse409 = {
  data: Login409
  status: 409
}

export type loginResponse500 = {
  data: Login500
  status: 500
}

export type loginResponseSuccess = (loginResponse200) & {
  headers: Headers;
};
export type loginResponseError = (loginResponse400 | loginResponse401 | loginResponse403 | loginResponse404 | loginResponse409 | loginResponse500) & {
  headers: Headers;
};

export type loginResponse = (loginResponseSuccess | loginResponseError)

export const getLoginUrl = () => {


  

  return `/bo/auth/login`
}

export const login = async (boLoginDto: BoLoginDto, options?: RequestInit): Promise<loginResponse> => {
  
  return fetcher<loginResponse>(getLoginUrl(),
  {      
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      boLoginDto,)
  }
);}
  


